var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"대장, 저 녀석이 성냥팔이야?","JPN":"隊長、あいつがマッチ売り？","ENG":"Is that the Matchmaker, Captain?","TWN":"隊長，他就是賣火柴的？"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그래. 보다시피 교활하기 짝이 없는 놈이다.","JPN":"ああ。見てのとおり、狡猾極まりない奴だ。","ENG":"Yes. As you can see, he's one hell of a conniving bastard.","TWN":"對，是一個極其陰險狡猾的人。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"하지만 자기가 당했던 수법을 그대로 써먹을 줄은 몰랐어.","JPN":"しかし、自分がやられた手口をそのまま使うとは思わなかった。","ENG":"But I didn't think he'd use the same trick that he fell for.","TWN":"不過沒想到你會用當年我用來對付你的手段。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"사람이 발전을 하려면 뭐든 배워야 하는 법이지.","JPN":"人は成長するために、何ごとでも学ばなければならないものだ。","ENG":"You've got to learn from your lessons if you want to get anywhere in life.","TWN":"人必須不斷學習才能進步嘛。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"군침 도는 미끼를 던져서 자기 앞마당으로 끌어들인 뒤 일망타진한다......","JPN":"よだれが出るほどの餌で縄張りに引き込んだ後、一網打尽にする……","ENG":"Throw out a tempting bait to draw the targets in and wipe 'em all out at once...","TWN":"用迷人的誘餌吸引到自己的地盤後一網打盡……"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"아주 좋은 방법이었어. 먼저 당했을 땐 나도 잠깐 아찔할 정도로.","JPN":"実にいい方法だ。先にやられた時は、この俺でも一瞬めまいがしたぐらいだ。","ENG":"That was pretty clever. It even got me startled for a few minutes.","TWN":"這個方法確實不錯。我上次確實被嚇壞了。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"배우는 자세가 좋군. 하지만 몸뚱어리만 믿고 방심하는 성격은 여전한 걸?","JPN":"学ぶ姿勢は立派だな。しかし、そんな風に体を張るくせに油断する性格は相変わらずだな？","ENG":"I like your attitude. But it seems you still haven't learned anything about letting down your guard.","TWN":"你熱愛學習的態度值得誇獎。但憑藉身體盲目自信的老毛病還是沒改哦？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"뭐?","JPN":"は？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"우리가 불나방도 아니고, 무작정 뛰어들었을 줄 알았나?","JPN":"俺たちが何も考えず、むやみに飛び込んできたとでも思ったのか？","ENG":"We're not lemmings. Did you think we'd just run off the cliff?","TWN":"你以為我們是盲目撲火的飛蛾嗎？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"오자마자 네 머리를 딸 수 있게 되어서 다행이군.","JPN":"着いて早々、貴様の頭を撃ち抜くことができて嬉しいぞ。","ENG":"I'm glad you showed up so early so we can take you out right away.","TWN":"我很高興，我馬上就能取你的命。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"최지훈! 쏴 버려!","JPN":"ゴトウ！　撃て！","ENG":"Shoot him down, Jihoon!","TWN":"崔智勳，開火！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"응답해, 최지훈! 왜 응답이 없나!","JPN":"応答しろ、ゴトウ！　ゴトウ！","ENG":"Come in, Jihoon! Why aren't you answering?","TWN":"回答我，崔智勳！回答我！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"응답할 필요 없어. 여기 왔으니까.","JPN":"わざわざ応答する必要はない。ここにいるからな。","ENG":"No need to yell over the comms. I'm right here.","TWN":"不用回答，人已經來了。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"최지훈! 저격 지점에 안 있고 왜 온 거야?!","JPN":"ゴトウ！　狙撃地点にいるはずが、なぜここにいるんだ？","ENG":"What the hell are you doing here? Why did you leave your sniping post?","TWN":"崔智勳！你為什麼不在狙擊點？！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"그렇게 소리치지 마. 귀 따가우니까.","JPN":"そんなに怒鳴るなよ。耳が痛い。","ENG":"Like I said, stop yelling. I'm going to go deaf.","TWN":"別大吼大叫，吼得我耳朵疼。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"너......","JPN":"お前……","ENG":"You...","TWN":"你……"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"설마, 저 놈에게 돈이라도 받아 먹은 거냐?","JPN":"まさか、あいつに金で買収されたのか？","ENG":"Did he pay you off or something?","TWN":"你難道收了那傢伙的錢嗎？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};